#[inline]
pub fn get_blk_device(id: usize) -> Option<Arc<dyn BlkDriver>> {
    let all_device = ALL_DEVICES.lock();
    let len = all_device.blk.len();
    match id < len {
        true => Some(all_device.blk[id].clone()),
        false => None,
    }
}

