    ($body: block) => {
        #[devices::linker_use($crate::DRIVERS_INIT)]
        #[linkme(crate = devices::linkme)]
        fn __driver_init() -> Option<alloc::sync::Arc<dyn devices::device::Driver>> {
            $body
        }
    };
    ($obj:expr, $func: expr) => {
        #[devices::linker_use($crate::DRIVERS_INIT)]
        #[linkme(crate = devices::linkme)]
        fn __driver_init() -> Option<alloc::sync::Arc<dyn devices::device::Driver>> {
            $crate::DRIVER_REGS.lock().insert($obj, $func);
            None
        }
    };
}

